#include <stdio.h>

int main() {
    double gold;
    char item = 'P';
    int count;
    int boost = 50;
    int level = 1;

    printf("골드 입력: \n");
    scanf("%lf", &gold);

    count = gold / 30;

    printf("보유 골드: %.6lf\n", gold);
    printf("공격력 증가: \"%d%%\" 달성!\n", boost * level);
    printf("%c %d개 보유 중\n", item, count);

    return 0;
}
